  30→
  31→/** Extra delay after network-idle to let JS-rendered content settle. */
  32→export const PAGE_STABILIZATION_DELAY_MS = 1_200;
  33→
  34→/** Timeout for the waitForFunction that checks for meaningful content. */
  35→export const FUNCTION_WAIT_TIMEOUT_MS = 20_000;
  36→
  37→/* ── Consent Handling ─────────────────────────────────────── */
  38→
  39→/** Maximum polling iterations when waiting for navigation after consent dismiss. */
